class Solution:
    def minProcessingTime(self, processorTime: List[int], tasks: List[int]) -> int:
        # Check constraints
        n = len(processorTime)
        if n > 25000:
            raise ValueError("Number of processors must be less than or equal to 25000")
        if len(tasks) != 4 * n:
            raise ValueError("Number of tasks must be exactly 4 * number of processors")

        # Sort processorTime in ascending order and tasks in descending order
        processorTime.sort()
        tasks.sort(reverse=True)

        # Assign the largest tasks to the earliest available processors
        max_time = 0
        task_index = 0
        for time in processorTime:
            # Assign 4 tasks to each processor
            for i in range(4):
                finish_time = time + tasks[task_index]
                if finish_time > max_time:
                    max_time = finish_time
                task_index += 1

        return max_time
